pub fn create_embedding_provider(
    provider: &str,
    api_key: Option<&str>,
    model: &str,
    dims: usize,
) -> Box<dyn EmbeddingProvider> {
    match provider {
        "openai" => {
            let key = api_key.unwrap_or("");
            Box::new(OpenAiEmbedding::new(
                "https://api.openai.com",
                key,
                model,
                dims,
            ))
        }
        "openrouter" => {
            let key = api_key.unwrap_or("");
            Box::new(OpenAiEmbedding::new(
                "https://openrouter.ai/api/v1",
                key,
                model,
                dims,
            ))
        }
        name if name.starts_with("custom:") => {
            let base_url = name.strip_prefix("custom:").unwrap_or("");
            let key = api_key.unwrap_or("");
            Box::new(OpenAiEmbedding::new(base_url, key, model, dims))
        }
        _ => Box::new(NoopEmbedding),
    }
}

/// Cosine similarity between two vectors. Returns 0.0‚Äì1.0.
pub fn cosine_similarity(a: &[f32], b: &[f32]) -> f32 {
    if a.len() != b.len() || a.is_empty() {
        return 0.0;
    }

    let mut dot = 0.0_f64;
    let mut norm_a = 0.0_f64;
    let mut norm_b = 0.0_f64;

    for (x, y) in a.iter().zip(b.iter()) {
        let x = f64::from(*x);
        let y = f64::from(*y);
        dot += x * y;
        norm_a += x * x;
        norm_b += y * y;
    }

    let denom = norm_a.sqrt() * norm_b.sqrt();
    if !denom.is_finite() || denom < f64::EPSILON {
        return 0.0;
    }

    let raw = dot / denom;
    if !raw.is_finite() {
        return 0.0;
    }

    // Clamp to [0, 1] ‚Äî embeddings are typically positive
    #[allow(clippy::cast_possible_truncation)]
    let sim = raw.clamp(0.0, 1.0) as f32;
    sim
}

/// A scored result for hybrid merging
#[derive(Debug, Clone)]
pub struct ScoredResult {
    pub id: String,
    pub vector_score: Option<f32>,
    pub keyword_score: Option<f32>,
    pub final_score: f32,
}

/// Hybrid merge: combine vector and keyword results with weighted fusion.
///
/// Normalizes each score set to [0, 1], then computes:
///   `final_score` = `vector_weight` * `vector_score` + `keyword_weight` * `keyword_score`
///
/// Deduplicates by id, keeping the best score from each source.
pub fn hybrid_merge(
    vector_results: &[(String, f32)],  // (id, cosine_similarity)
    keyword_results: &[(String, f32)], // (id, bm25_score)
    vector_weight: f32,
    keyword_weight: f32,
    limit: usize,
) -> Vec<ScoredResult> {

/// Default half-life (days) for time decay in memory loading.
const LOADER_DECAY_HALF_LIFE_DAYS: f64 = 7.0;

/// Score boost applied to `Core` category memories so durable facts and
/// preferences surface even when keyword/semantic similarity is moderate.
const CORE_CATEGORY_SCORE_BOOST: f64 = 0.3;

/// Over-fetch factor: retrieve more candidates than the output limit so
/// that Core boost and re-ranking can select the best subset.
const RECALL_OVER_FETCH_FACTOR: usize = 2;

impl MemoryLoader for DefaultMemoryLoader {
    async fn load_context(
        &self,
        memory: &dyn Memory,
        user_message: &str,
    ) -> anyhow::Result<String> {
        // Over-fetch so Core-boosted entries can compete fairly after re-ranking.
        let fetch_limit = self.limit * RECALL_OVER_FETCH_FACTOR;
        let mut entries = memory.recall(user_message, fetch_limit, None).await?;
        if entries.is_empty() {
            return Ok(String::new());
        }

        // Apply time decay: older non-Core memories score lower.
        decay::apply_time_decay(&mut entries, LOADER_DECAY_HALF_LIFE_DAYS);

        // Apply Core category boost and filter by minimum relevance.
        let mut scored: Vec<_> = entries
            .iter()
            .filter(|e| !memory::is_assistant_autosave_key(&e.key))
            .filter_map(|e| {
                let base = e.score.unwrap_or(self.min_relevance_score);
                let boosted = if e.category == MemoryCategory::Core {
                    (base + CORE_CATEGORY_SCORE_BOOST).min(1.0)
                } else {
                    base
                };
                if boosted >= self.min_relevance_score {
                    Some((e, boosted))
                } else {
                    None
                }
            })
            .collect();

        // Sort by boosted score descending, then truncate to output limit.
        scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
        scored.truncate(self.limit);

        if scored.is_empty() {
            return Ok(String::new());
        }

        let mut context = String::from("[Memory context]\n");
        for (entry, _) in &scored {
            let _ = writeln!(context, "- {}: {}", entry.key, entry.content);
        }
        context.push('\n');
        Ok(context)
    }
}

use super::traits::{MemoryCategory, MemoryEntry};
use chrono::{DateTime, Utc};

/// Default half-life in days for time-decay scoring.
/// After this many days, a non-Core memory's score drops to 50%.
const DEFAULT_HALF_LIFE_DAYS: f64 = 7.0;

/// Apply exponential time decay to memory entry scores.
///
/// - `Core` memories are exempt ("evergreen") ‚Äî their scores are never decayed.
/// - Entries without a parseable RFC3339 timestamp are left unchanged.
/// - Entries without a score (`None`) are left unchanged.
///
/// Decay formula: `score * 2^(-age_days / half_life_days)`
pub fn apply_time_decay(entries: &mut [MemoryEntry], half_life_days: f64) {
    let half_life = if half_life_days <= 0.0 {
        DEFAULT_HALF_LIFE_DAYS
    } else {
        half_life_days
    };

    let now = Utc::now();

    for entry in entries.iter_mut() {
        // Core memories are evergreen ‚Äî never decay
        if entry.category == MemoryCategory::Core {
            continue;
        }

        let score = match entry.score {
            Some(s) => s,
            None => continue,
        };

        let ts = match DateTime::parse_from_rfc3339(&entry.timestamp) {
            Ok(dt) => dt.with_timezone(&Utc),
            Err(_) => continue,
        };

        let age_days = now.signed_duration_since(ts).num_seconds().max(0) as f64 / 86_400.0;

        let decay_factor = (-age_days / half_life * std::f64::consts::LN_2).exp();
        entry.score = Some(score * decay_factor);
    }
}

/// Accumulates conversation turns for periodic fact extraction.
///
/// Decoupled from `history` so tool/summary messages do not affect
/// the extraction window.
pub(crate) struct TurnBuffer {
    turns: Vec<(String, String)>,
    total_chars: usize,
    last_extract_succeeded: bool,
}

/// Outcome of a single extraction attempt.
pub(crate) struct ExtractionResult {
    /// Number of facts successfully stored to Core memory.
    pub stored: usize,
    /// `true` when the LLM confirmed there are no new facts (or all parsed
    /// facts were intentionally skipped). `false` on LLM/store failures.
    pub no_facts: bool,
}

impl TurnBuffer {
    pub fn new() -> Self {
        Self {
            turns: Vec::new(),
            total_chars: 0,
            last_extract_succeeded: true,
        }
    }

    /// Record a completed conversation turn.
    pub fn push(&mut self, user_msg: &str, assistant_resp: &str) {
        self.total_chars += user_msg.chars().count() + assistant_resp.chars().count();
        self.turns
            .push((user_msg.to_string(), assistant_resp.to_string()));
    }

    /// Whether the buffer has accumulated enough turns and content to
    /// justify an extraction call.
    pub fn should_extract(&self) -> bool {
        self.turns.len() >= EXTRACT_TURN_INTERVAL && self.total_chars >= EXTRACT_MIN_CHARS
    }

    /// Drain all buffered turns and return them for extraction.
    /// Resets character counter; `last_extract_succeeded` is cleared
    /// until the caller confirms success via [`mark_extract_success`].
    pub fn drain_for_extraction(&mut self) -> Vec<(String, String)> {
        self.total_chars = 0;
        self.last_extract_succeeded = false;
        std::mem::take(&mut self.turns)
    }

    /// Mark the most recent extraction as successful.
    pub fn mark_extract_success(&mut self) {
        self.last_extract_succeeded = true;
    }

    /// Whether there are buffered turns that have not been extracted.
    pub fn is_empty(&self) -> bool {
        self.turns.is_empty()
    }

    /// Whether compaction should fall back to its own `flush_durable_facts`.
    /// This returns `true` when un-extracted turns remain **or** the last
    /// extraction failed (so durable facts may have been lost).
    pub fn needs_compaction_fallback(&self) -> bool {
        !self.turns.is_empty() || !self.last_extract_succeeded
    }
}

/// Extract durable facts from a conversation transcript and store them as
/// `Core` memories. Called before compaction discards old messages.
///
/// Best-effort: failures are logged but never block compaction.
/// Returns `true` when facts were stored **or** the LLM confirmed
/// there are none (`NONE` response). Returns `false` on LLM/store
/// failures so the caller can avoid marking extraction as successful.
async fn flush_durable_facts(
    provider: &dyn Provider,
    model: &str,
    transcript: &str,
    memory: &dyn Memory,
    session_id: Option<&str>,
) -> bool {
    const FLUSH_SYSTEM: &str = "\
You extract durable facts from a conversation that is about to be compacted. \
Output ONLY facts worth remembering long-term ‚Äî user preferences, project decisions, \
technical constraints, commitments, or important discoveries.\n\
\n\
NEVER extract secrets, API keys, tokens, passwords, credentials, \
or any sensitive authentication data. If the conversation contains \
such data, skip it entirely.\n\
\n\
Output one fact per line, prefixed with a short key in brackets. \
Example:\n\
[preferred_language] User prefers Rust over Go\n\
[db_choice] Project uses PostgreSQL 16\n\
If there are no durable facts, output exactly: NONE";

    for line in response.lines() {
        if stored >= COMPACTION_MAX_FLUSH_FACTS {
            break;
        }
        let line = line.trim();
        if line.is_empty() {
            continue;
        }
        // Parse "[key] content" format
        if let Some((key, content)) = parse_fact_line(line) {
            parsed += 1;
            // Scrub secrets from extracted content.
            let clean = crate::providers::scrub_secret_patterns(content);
            if should_skip_redacted_fact(&clean, content) {
                tracing::info!(
                    "Skipped compaction fact '{key}': only secret shell remains after redaction"
                );
                continue;
            }
            let norm_key = normalize_fact_key(key);
            if norm_key.is_empty() {
                continue;
            }
            let prefixed_key = format!("auto_{norm_key}");
            if let Err(e) = memory
                .store(&prefixed_key, &clean, MemoryCategory::Core, session_id)
                .await
            {
                tracing::warn!("Failed to store compaction fact '{prefixed_key}': {e}");
                store_failures += 1;
            } else {
                stored += 1;
            }
        }
    }
    if stored > 0 {
        tracing::info!("Pre-compaction flush: stored {stored} durable fact(s) to Core memory");
    }
    // Success when at least one fact was parsed and no store failures
    // occurred, OR all parsed facts were intentionally skipped.
    // Unparseable output (parsed == 0) is treated as failure.
    parsed > 0 && store_failures == 0
}

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
struct HygieneReport {
    archived_memory_files: u64,
    archived_session_files: u64,
    purged_memory_archives: u64,
    purged_session_archives: u64,
    pruned_conversation_rows: u64,
}

impl HygieneReport {
    fn total_actions(&self) -> u64 {
        self.archived_memory_files
            + self.archived_session_files
            + self.purged_memory_archives
            + self.purged_session_archives
            + self.pruned_conversation_rows
    }
}

/// Run memory/session hygiene if the cadence window has elapsed.
///
/// This function is intentionally best-effort: callers should log and continue on failure.
pub fn run_if_due(config: &MemoryConfig, workspace_dir: &Path) -> Result<()> {
    if !config.hygiene_enabled {
        return Ok(());
    }

    if !should_run_now(workspace_dir)? {
        return Ok(());
    }

    let report = HygieneReport {
        archived_memory_files: archive_daily_memory_files(
            workspace_dir,
            config.archive_after_days,
        )?,
        archived_session_files: archive_session_files(workspace_dir, config.archive_after_days)?,
        purged_memory_archives: purge_memory_archives(workspace_dir, config.purge_after_days)?,
        purged_session_archives: purge_session_archives(workspace_dir, config.purge_after_days)?,
        pruned_conversation_rows: prune_conversation_rows(
            workspace_dir,
            config.conversation_retention_days,
        )?,
    };

    write_state(workspace_dir, &report)?;

    if report.total_actions() > 0 {
        tracing::info!(
            "memory hygiene complete: archived_memory={} archived_sessions={} purged_memory={} purged_sessions={} pruned_conversation_rows={}",
            report.archived_memory_files,
            report.archived_session_files,
            report.purged_memory_archives,
            report.purged_session_archives,
            report.pruned_conversation_rows,
        );
    }

    Ok(())
}

//! Memory snapshot ‚Äî export/import core memories as human-readable Markdown.
//!
//! **Atomic Soul Export**: dumps `MemoryCategory::Core` from SQLite into
//! `MEMORY_SNAPSHOT.md` so the agent's "soul" is always Git-visible.
//!
//! **Auto-Hydration**: if `brain.db` is missing but `MEMORY_SNAPSHOT.md` exists,
//! re-indexes all entries back into a fresh SQLite database.

use anyhow::Result;
use chrono::Local;
use rusqlite::{params, Connection};
use std::fmt::Write;
use std::fs;
use std::path::{Path, PathBuf};

/// Filename for the snapshot (lives at workspace root for Git visibility).
pub const SNAPSHOT_FILENAME: &str = "MEMORY_SNAPSHOT.md";

/// Header written at the top of every snapshot file.
const SNAPSHOT_HEADER: &str = "# \u{1f9e0} ZeroClaw Memory Snapshot\n\n\
    > Auto-generated by ZeroClaw. Do not edit manually unless you know what you're doing.\n\
    > This file is the \"soul\" of your agent ‚Äî if `brain.db` is lost, start the agent\n\
    > in this workspace and it will auto-hydrate from this file.\n\n";

/// Check if we should auto-hydrate on startup.
///
/// Returns `true` if:
/// 1. `brain.db` does NOT exist (or is empty)
/// 2. `MEMORY_SNAPSHOT.md` DOES exist
pub fn should_hydrate(workspace_dir: &Path) -> bool {
    let db_path = workspace_dir.join("memory").join("brain.db");
    let snapshot = snapshot_path(workspace_dir);

    let db_missing_or_empty = if db_path.exists() {
        // DB exists but might be empty (freshly created)
        fs::metadata(&db_path)
            .map(|m| m.len() < 4096) // SQLite header is ~4096 bytes minimum
            .unwrap_or(true)
    } else {
        true
    };

    db_missing_or_empty && snapshot.exists()
}

/// Response cache backed by a dedicated SQLite database.
///
/// Lives alongside `brain.db` as `response_cache.db` so it can be
/// independently wiped without touching memories.
pub struct ResponseCache {
    conn: Mutex<Connection>,
    #[allow(dead_code)]
    db_path: PathBuf,
    ttl_minutes: i64,
    max_entries: usize,
}

/// Build a deterministic cache key from model + system prompt + user prompt.
pub fn cache_key(model: &str, system_prompt: Option<&str>, user_prompt: &str) -> String {
    let mut hasher = Sha256::new();
    hasher.update(model.as_bytes());
    hasher.update(b"|");
    if let Some(sys) = system_prompt {
        hasher.update(sys.as_bytes());
    }
    hasher.update(b"|");
    hasher.update(user_prompt.as_bytes());
    let hash = hasher.finalize();
    format!("{:064x}", hash)
}

/// Look up a cached response. Returns `None` on miss or expired entry.
pub fn get(&self, key: &str) -> Result<Option<String>> {
    let conn = self.conn.lock();

    let now = Local::now();
    let cutoff = (now - Duration::minutes(self.ttl_minutes)).to_rfc3339();

    let mut stmt = conn.prepare(
        "SELECT response FROM response_cache
         WHERE prompt_hash = ?1 AND created_at > ?2",
    )?;

    let result: Option<String> = stmt.query_row(params![key, cutoff], |row| row.get(0)).ok();

    if result.is_some() {
        // Bump hit count and accessed_at
        let now_str = now.to_rfc3339();
        conn.execute(
            "UPDATE response_cache
             SET accessed_at = ?1, hit_count = hit_count + 1
             WHERE prompt_hash = ?2",
            params![now_str, key],
        )?;
    }

    Ok(result)
}
